mapper.select:
/* StatsMgmtMapper.selectStatsMgmtListExcel */ SELECT SUB.CONTRACT_NUM as contractNum , SUBSTR(JAI.SIM_START_DT,0,8) AS simStrtDt , DECODE(JAI.APP_END_DATE, '99991231000000', SUBSTR(JAI.SIM_END_DT,0,8), SUBSTR(JAI.APP_END_DATE,0,8)) AS simEndDt , CASE WHEN TO_DATE(JAI.APP_END_DATE, 'YYYYMMDDHH24MISS') < SYSDATE THEN '해지' WHEN JAI.APP_END_DATE = '99991231000000' THEN CASE WHEN TO_DATE(JAI.SIM_END_DT, 'YYYYMMDDHH24MISS') < SYSDATE THEN '해지' ELSE '사용중' END ELSE '사용중' END AS simStatNm , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS lstComActvDate , DECODE(SUB.SUB_STATUS, 'C', TO_CHAR(TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD'), 'YYYY-MM-DD'), '') AS tmntDt , NVL(TRIM(SUBSTR(REQ.FST_MODEL_INFO, 21 , 30)), REQ.REQ_USIM_NAME) AS fstModelInfo , REQ.FST_RATE_CD as fstRateCd , REQ.FST_RATE_NM as fstRateNm , SUB.OPEN_AGNT_CD as openAgntCd , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS openAgntNm , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) AS AGE , DECODE(MOD(SUBSTR(CRYPTO_AES256.DEC_AES(SUB.USER_SSN),7,1), 2), 1, '남', '여') AS sexNm , CASE WHEN DCH.CONTRACT_NUM IS NOT NULL AND DVC_REQ.OPER_TYPE = 'HDN3' THEN LRT.DATA_TYPE ELSE FRT.DATA_TYPE END AS dataType , FN_GET_CODENM('RCP9004', CASE WHEN DCH.CONTRACT_NUM IS NOT NULL AND DVC_REQ.OPER_TYPE = 'HDN3' THEN 'MM' ELSE REQ.REQ_BUY_TYPE END ) AS reqBuyType , SUB.SUB_STATUS as subStatus , FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) AS subStatusNm , TO_NUMBER(SUBSTR(REQ.SIM_INFO, 3, 3)) AS simEnggCnt , SUB_LINK_NAME as cstmrNm , SUB_LINK_NAME AS subLinkNameMsk , FN_GET_CODENM('RCP0007', REQ.ON_OFF_TYPE ) AS onOffType , AGR.DLVRY_NAME as dlvryName , AGR.DLVRY_MOBILE_FN || AGR.DLVRY_MOBILE_MN || AGR.DLVRY_MOBILE_RN AS phonCtn , AGR.DLVRY_POST as dlvryPost , AGR.DLVRY_ADDR || AGR.DLVRY_ADDR_DTL AS dlvryFullAddr , AGR.DLVRY_ADDR as DlvryAddr , AGR.DLVRY_ADDR_DTL as DlvryAddrDtl , PRESENT_CODE as presentCode , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'presentCode' AND DTL_CD = AGR.PRESENT_CODE ) AS presentNm , AGRM_MEMO as agrmMemo , AGR.SEQ , SUB.SUBSCRIBER_NO as subscriberNo , DECODE(AGR.ORDER_TYPE, '01', '홈페이지', '02', 'SMS', AGR.ORDER_TYPE) as orderTypeNm FROM MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL REQ , MSP_DVC_CHG_AGNT_HST DCH , MSP_REQUEST DVC_REQ , MSP_RATE_MST FRT , MSP_RATE_MST LRT , MSP_JUO_ADD_INFO JAI , (SELECT B.CONTRACT_NUM, B.SEQ, B.DLVRY_NAME, B.DLVRY_MOBILE_FN, B.DLVRY_MOBILE_MN, B.DLVRY_MOBILE_RN, B.DLVRY_POST, B.DLVRY_ADDR, B.DLVRY_ADDR_DTL, B.PRESENT_CODE, B.AGRM_MEMO, NVL(B.ORDER_TYPE, '01') AS ORDER_TYPE, B.REGST_DTTM FROM (SELECT CONTRACT_NUM , MAX(SEQ) AS SEQ FROM MCP_REQUEST_AGRM@DL_MCP GROUP BY CONTRACT_NUM) A , MCP_REQUEST_AGRM@DL_MCP B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.SEQ = B.SEQ) AGR WHERE SUB.PPPO = 'PO' AND SUB.CONTRACT_NUM = REQ.CONTRACT_NUM AND REQ.SIM_INFO IS NOT NULL AND REQ.FST_RATE_CD = FRT.RATE_CD AND REQ.LST_RATE_CD = LRT.RATE_CD AND JAI.CONTRACT_NUM = AGR.CONTRACT_NUM(+) AND AGR.REGST_DTTM(+) BETWEEN TO_DATE(SUBSTR(JAI.SIM_START_DT, 0, 8) , 'YYYYMMDD') AND TO_DATE(SUBSTR(JAI.SIM_START_DT, 0, 8), 'YYYYMMDD') + 7 AND SUB.CONTRACT_NUM = DCH.CONTRACT_NUM(+) AND DCH.APPL_END_DTTM(+) = '99991231000000' AND DCH.REQUEST_KEY(+) IS NOT NULL AND DCH.REQUEST_KEY = DVC_REQ.REQUEST_KEY(+) AND SUB.CONTRACT_NUM = JAI.CONTRACT_NUM AND JAI.EVNT_CD = 'SIM' AND JAI.GRNT_INSR_STAT_CD = 'A'
AND SUBSTR(JAI.SIM_START_DT, 0, 8) BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUB.SUB_STATUS = #{subStatus}
AND (SUB.CONTRACT_NUM = #{searchName} OR SUB.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SUB.SUB_LINK_NAME LIKE #{searchName} || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND REQ.ON_OFF_TYPE = #{onOffType}
AND AGR.ORDER_TYPE = #{orderType}
ORDER BY contractNum DESC, JAI.SIM_START_DT, simEndDt , SUB.SUB_STATUS, SUB.OPEN_AGNT_CD
